mapper.select:
SELECT m.name, d.district_name AS district, m.phone, m.reg_date AS registered_at FROM erp_member m LEFT JOIN erp_district d ON m.district_id = d.district_id
AND (m.name LIKE '%' || #{keyword} || '%' OR m.phone LIKE '%' || #{keyword} || '%')
ORDER BY m.reg_date DESC LIMIT #{limit} OFFSET #{offset}
